function Pod1ClickFunc(MouseEvent:Object):void
{	
	vM = new Array();
	for(var i:int=0; i<Main.Slovo.length; ++i) if(Par.Neiz[i] == '__') vM[vM.length] = i;
	var m:int = (Math.random()*(vM.length))|0;
	Par.Neiz[vM[m]] = Main.Slovo[vM[m]];
	for(var b:int=0; b<Main.Bykvi.length; ++b)
		if (Main.Slovo[vM[m]] == Main.Bykvi[b])
		{
			Par.YesNo = new OneResultMov(3);
			Main.sYes.play(0, 1);
			Par.Knop['Kn'+b].addChild(Par.YesNo);
			Par.Knop['Kn'+b].mouseEnabled = false;
			Par.Knop['Kn'+b].mouseChildren = false;
			Par.Knop['Kn'+b].alpha = 0.5;
			break;
		}
	for(i=0; i<Main.Slovo.length; ++i)
		if(Main.Slovo[i] == Par.Neiz[vM[m]]) Par.Neiz[i] = Main.Slovo[i];
	Par.Txt.text = Main.Transl[45] + ' ';
	for(i=0; i<Main.Slovo.length; ++i) Par.Txt.appendText(Par.Neiz[i] + ' ');
	Main.Game.Minimazer();
	Pds2.Pod1.alpha = 0.5;
	Pds2.Pod1.mouseEnabled = false;
	Main.Save.data.Pd1 = 1;
	if(Pds2.Pod2.alpha == 0.5) play();
	else (parent as Object).PdN.Txt.text = Main.Transl[65] +' 1 '+ Main.Transl[66] + Main.Transl[67];
}

