	this['Kn'+iBykNumb].gotoAndStop(Dat.ErrArr[2][iBykNumb]+1);

	if(checkLetter)
	{
		var checkUnfind:Boolean; 
		for(var i:int=0; i<Dat.ErrArr[0].length; ++i)
		{
			if(Dat.ErrArr[0][i]==varka) Neiz[i] = varka;
			else
				if(!checkUnfind && Neiz[i]=='_') checkUnfind = true;
		}
		if(!isHint)
		{
			tempSound = new Try1();
			Main.SoundChecker(tempSound);
			if(Vis.HeroMov.Mov.currentFrame==5) Vis.HeroMov.Mov.gotoAndPlay(6);
		}
		if(!checkUnfind) ReztLoader(1);
		else Txt.text = Neiz.join(' ');
	}
	else
		if(!isHint)
		{
			/*if(Vibration.isSupported && Dat.Settings[4]==2)
			{
				BadVibr = new Vibration();
				BadVibr.vibrate(150);
			}*/
			tempSound = new Try2();
