	{
		Dat.ErrArr = new Array();
		Dat.ErrArr[1] = new <int>[-1,0,0,0,0];
	}
	Dat.ErrArr[2] = null;
	Dat.ErrArr[0] = new Array();
	Dat.ErrArr[3] = new <Boolean>[true,true];
	Dat.ErrArr[4] = new String();
}
function Cloner(source:Object):* 
{ 
    var myBA:ByteArray = new ByteArray(); 
    myBA.writeObject(source); 
    myBA.position = 0;
    return(myBA.readObject());
}
