function SoundChecker(Path:Sound, Looped:Boolean=false):void
{
	var tempSnd:Sound = Path;
	if(Dat.Settings[3]==2)
		if(Looped)
		{
			if(MainSndCnannel) MainSndCnannel.stop();
			if(SndTrsTimer && SndTrsTimer.running) SndTrsTimer.reset();
			else SndTrsTimer = new Timer(50, 25);
			MainSndCnannel = tempSnd.play(0,999);
			MainSoundTransform = MainSndCnannel.soundTransform;
			MainSoundTransform.volume = 0;
			MainSndCnannel.soundTransform = MainSoundTransform;
			SndTrsTimer.addEventListener(TimerEvent.TIMER, TimerSwitcher);
			SndTrsTimer.start();
		}
		else SideSndCnannel = tempSnd.play(0,1);
	tempSnd = null;
}
function TimerSwitcher(event:TimerEvent):void
{
	if(MainSndCnannel)
	{
		if(MainSoundTransform.volume < 1) MainSoundTransform.volume += 0.04;
		else MainSoundTransform.volume = 1;
		MainSndCnannel.soundTransform = MainSoundTransform;
	}
	else SndTrsTimer.reset();
}
