function LangChange(LngInp:String):void
{
	var tempInt:int;
	try	{tempInt = Dat.Settings[3];}
	catch(e:Error) {tempInt = 1;}

	Lang.data.LngArr[1] = LngInp;
	Save = SharedObject.getLocal('SaveHangman'+LngInp);
	Dat = Save.data;

	if(!Dat.Records)
	{
		Dat.Records = new Array();
		Dat.Records[0] = new <Number>[0,0,0,0]; 
		Dat.Records[1] = new <Number>[0,0];
		Dat.Records[2] = new <Number>[0,0,0];
	}
	if(!Dat.ErrArr) Delet();
	if(!Dat.Settings || Dat.Settings.length<6)
		Dat.Settings = new <int>[2,2,0,2,2,1];
	wordsBase = new Database(this, LngInp);
	if(Menu) Menu.LangChecker();

	tempInt -= Dat.Settings[3];
	if(tempInt<0) MusicMenuIncome();
	else
		if(tempInt>0) MusicClearSound();
}
function ResizeXY(objParam:Object, xFixed:Boolean=false, yFixed:Boolean=false):void
{
	var tempRes:Number;
	if(Capabilities.screenResolutionX / 800 > Capabilities.screenResolutionY / 480)
	{
		if(!xFixed)
		{
			tempRes = Capabilities.screenResolutionX / 800 - Capabilities.screenResolutionY / 480;
			if(objParam.x > 400) objParam.x += 200 * tempRes;
			else objParam.x -= 200 * tempRes
		}
	}
	else
		if(!yFixed)
		{
			tempRes = Capabilities.screenResolutionY / 480 - Capabilities.screenResolutionX / 800;
			if(objParam.y > 240) objParam.y += 120 * tempRes;
			else objParam.y -= 120 * tempRes
		}
}
